// Parse AI Agent output
const aiOutput = $json.output || '';

// Try to extract JSON from AI response
let parsed;
try {
  // Remove markdown code blocks if present
  const cleaned = aiOutput.replace(/```json\n?|```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Failed to parse AI output as JSON: ${aiOutput}`);
}

const isGroup = parsed.isGroup === true;
const target = parsed.target || '';
const text = parsed.text || '';

if (!target || !text) {
  throw new Error('AI did not extract target and text correctly');
}

return {
  isGroup: isGroup,
  target: target,
  text: text,
  // For phone: normalize the number
  number: isGroup ? '' : target.replace(/[\s\+]/g, '').replace(/^00/, ''),
  // For group: store name for matching
  groupName: isGroup ? target.toLowerCase() : ''
};

const groupName = $('Parse AI Output').first().json.groupName;

// Get all groups from previous node (n8n splits array into multiple items)
const groups = $input.all().map(item => item.json);

if (groups.length === 0) {
  throw new Error('Keine WhatsApp-Gruppen verfügbar. Ist WhatsApp verbunden?');
}

// Find matching group using partial match (case-insensitive)
const matchedGroup = groups.find(g =>
  (g.subject?.toLowerCase() || '').includes(groupName)
);

if (!matchedGroup) {
  const availableGroups = groups.map(g => g.subject).filter(Boolean).join(', ');
  throw new Error(`Gruppe "${groupName}" wurde nicht gefunden. Verfügbare Gruppen: ${availableGroups || '(keine)'}`);
}

// Return the group JID (format: 120363xxx@g.us)
return {
  number: matchedGroup.id,
  text: $('Parse AI Output').first().json.text,
  groupFound: true,
  groupName: matchedGroup.subject
};

// Extract vCard URLs from PROPFIND - FIXED REGEX (namespace-agnostic)
const xml = $input.first().json.data || '';
const searchName = $('Parse AI Output').first().json.target?.toLowerCase() || '';
const messageText = $('Parse AI Output').first().json.text || '';

const MAX_CONTACTS = 50;

console.log(`Searching for: "${searchName}"`);

if (!xml || xml.length < 100) {
  throw new Error('Keine XML-Daten von CardDAV erhalten. Prüfe Credentials und Adressbuch-ID.');
}

// FIXED: Namespace-agnostic regex for href with .vcf
// Supports: <D:href>, <d:href>, <href>, with/without whitespace
const hrefRegex = /<(?:[dD]:)?href[^>]*>\s*([^<]*\.vcf)\s*<\/(?:[dD]:)?href>/gi;

const urls = [];
let match;

while ((match = hrefRegex.exec(xml)) !== null && urls.length < MAX_CONTACTS) {
  const url = match[1].trim();
  if (url) {
    urls.push(url);
  }
}

if (urls.length === 0) {
  console.error('ERROR: No .vcf URLs found in XML response!');
  console.log('XML Preview:', xml.substring(0, 500));

  // Debug: Show what we can find
  const anyHref = xml.match(/<[^>]*href[^>]*>/gi);
  if (anyHref) {
    console.log('Found href tags:', anyHref.slice(0, 3));
  }

  throw new Error('Keine vCard-URLs gefunden. Prüfe die CardDAV Credentials und Adressbuch-ID (/carddav/32).');
}

const total = (xml.match(/<(?:[dD]:)?href[^>]*>[^<]*\.vcf[^<]*<\/(?:[dD]:)?href>/gi) || []).length;
console.log(`Processing ${urls.length} of ${total} contacts (parallel fetch)`);

// Return URLs as separate items - n8n will process them in PARALLEL
return urls.map(url => ({
  json: {
    contactUrl: url,
    searchName: searchName,
    text: messageText
  }
}));

// Parse vCard from GET response
const vCardText = $json.vCardData || $json.data || '';

// Get searchName and text from Parse Contact URLs using item index
const itemIndex = $itemIndex;
const parseContactUrlsItems = $items('Parse Contact URLs');
const searchName = parseContactUrlsItems[itemIndex]?.json.searchName?.toLowerCase() || '';
const messageText = parseContactUrlsItems[itemIndex]?.json.text || '';

if (!vCardText.includes('BEGIN:VCARD')) {
  return null; // Skip invalid vCards
}

const lines = vCardText.split(/\r?\n/);
const contact = {
  fullName: '',
  firstName: '',
  lastName: '',
  phones: [],
  emails: [],
  searchName: searchName,
  messageText: messageText
};

for (const line of lines) {
  // FN: Full Name
  if (line.startsWith('FN:')) {
    contact.fullName = line.substring(3).trim();
  }

  // N: Structured Name (Lastname;Firstname;Middle;Prefix;Suffix)
  if (line.startsWith('N:')) {
    const parts = line.substring(2).split(';');
    contact.lastName = (parts[0] || '').trim();
    contact.firstName = (parts[1] || '').trim();
  }

  // TEL: Phone (verschiedene Formate: TEL;TYPE=CELL:..., TEL:...)
  if (line.startsWith('TEL')) {
    const telMatch = line.match(/TEL[^:]*:(.+)/);
    if (telMatch) {
      const number = telMatch[1].trim();
      const typeMatch = line.match(/TYPE=([^;:]+)/);
      contact.phones.push({
        number: number,
        type: typeMatch ? typeMatch[1].toUpperCase() : 'OTHER'
      });
    }
  }

  // EMAIL
  if (line.startsWith('EMAIL')) {
    const emailMatch = line.match(/EMAIL[^:]*:(.+)/);
    if (emailMatch) {
      contact.emails.push(emailMatch[1].trim());
    }
  }
}

// Only return contacts with a name
if (!contact.fullName && !contact.firstName) {
  return null;
}

return { json: contact };

// Collect all parsed contacts and select best match
const contacts = $input.all().map(item => item.json);
const searchName = contacts[0]?.searchName?.toLowerCase() || '';
const messageText = contacts[0]?.messageText || '';

if (contacts.length === 0) {
  throw new Error(`No contacts found for: "${searchName}"`);
}

console.log(`Scoring ${contacts.length} contacts for search: "${searchName}"`);

// Best Match Search with Scoring
let bestMatch = null;
let highestScore = 0;

for (const contact of contacts) {
  const fullName = (contact.fullName || '').toLowerCase();
  const firstName = (contact.firstName || '').toLowerCase();
  const lastName = (contact.lastName || '').toLowerCase();

  // Scoring: exact match > contains > partial
  let score = 0;
  if (fullName === searchName) score = 100;
  else if (fullName.includes(searchName)) score = 80;
  else if (firstName === searchName || lastName === searchName) score = 70;
  else if (firstName.includes(searchName) || lastName.includes(searchName)) score = 50;

  if (score > highestScore) {
    highestScore = score;
    bestMatch = contact;
  }
}

if (!bestMatch || highestScore < 50) {
  const availableContacts = contacts.map(c => c.fullName).filter(Boolean).join(', ');
  throw new Error(`No matching contact for "${searchName}". Available: ${availableContacts}`);
}

console.log(`Best match: "${bestMatch.fullName}" (score: ${highestScore})`);

return {
  json: {
    contact: bestMatch,
    matchScore: highestScore,
    searchName: searchName,
    messageText: messageText
  }
};

// Extract and normalize phone number from best match
const contact = $json.contact;
const messageText = $json.messageText;

if (!contact || !contact.phones || contact.phones.length === 0) {
  throw new Error(`Contact "${contact?.fullName || 'unknown'}" has no phone number`);
}

// Prioritize CELL/MOBILE phones
const cellPhones = contact.phones.filter(p => 
  p.type === 'CELL' || p.type === 'MOBILE' || p.type === 'VOICE'
);

const phoneToUse = cellPhones.length > 0 
  ? cellPhones[0].number 
  : contact.phones[0].number;

// Normalize phone number
let normalized = phoneToUse
  .replace(/[\s\-\(\)]/g, '')
  .replace(/^00/, '+')
  .replace(/^\+/, '');

// Handle Austrian local numbers
if (normalized.startsWith('0')) {
  normalized = '43' + normalized.substring(1);
}

return {
  number: normalized,
  text: messageText,
  contactName: contact.fullName,
  originalPhone: phoneToUse,
  matchScore: $json.matchScore
};
